
.status-bar {
  width: 100%;
  max-width: 720px;
  background-color: var(--c-cream);
  border: 2px solid var(--c-dark-gold);
  font-family: var(--font-body);
  color: var(--c-text);
  font-size: 13px;
  line-height: 1.4;
  margin: 0 auto;
  padding: 10px 14px;
}

.location-row {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 4px;

  .label {
    font-weight: 700;
    color: var(--c-dark-gold);
    min-width: 36px;
  }
  .value {
    color: var(--c-mid-blue);
    font-weight: 600;
  }
}

.divider {
  height: 1px;
  background: var(--c-warm-grey);
  margin: 8px 0;
  opacity: 0.4;
}

.char-section {
  .char-name {
    font-weight: 700;
    font-size: 14px;
    color: var(--c-deep-blue);
    margin-bottom: 6px;
  }

  .stats-grid {
    display: flex;
    flex-direction: column;
    gap: 5px;
  }

  .stat-item {
    display: flex;
    align-items: center;
    gap: 6px;
  }

  .stat-label {
    min-width: 40px;
    color: var(--c-warm-grey);
    font-size: 12px;
  }

  .bar-container {
    flex: 1;
    height: 10px;
    background: #e0ddd5;
    border-radius: 3px;
    overflow: hidden;
  }

  .bar-fill {
    height: 100%;
    border-radius: 3px;
    transition: width 0.4s ease;
  }

  .bar-fill.affection {
    background: linear-gradient(90deg, var(--c-light-blue), var(--c-mid-blue));
  }
  .bar-fill.trust {
    background: linear-gradient(90deg, #8bc98b, #5a9a5a);
  }
  .bar-fill.obey {
    background: linear-gradient(90deg, var(--c-gold), var(--c-dark-gold));
  }

  .stat-value {
    min-width: 28px;
    text-align: right;
    font-size: 12px;
    font-weight: 600;
    color: var(--c-text);
  }

  .stage-badge {
    display: inline-block;
    margin-top: 6px;
    padding: 2px 10px;
    border-radius: 10px;
    font-size: 12px;
    font-weight: 700;
    color: #fff;
  }

  .stage-resist { background: #8b3a3a; }
  .stage-waver { background: #b8860b; }
  .stage-sink { background: #4a6fa5; }

  .char-status {
    margin-top: 4px;
    color: var(--c-warm-grey);
    font-size: 12px;
    font-style: italic;
  }
}

.qs-section {
  .qs-name {
    font-weight: 700;
    font-size: 14px;
    color: var(--c-deep-blue);
    margin-bottom: 2px;
  }
  .qs-status {
    color: var(--c-warm-grey);
    font-size: 12px;
    font-style: italic;
  }
}
